// Poisson sampler (Knuth's algorithm). Pure JS — the worker runs in a Blob URL
// so no imports are available. Given an expected goal count 'lambda', returns a
// non-negative integer drawn from Poisson(lambda). Goals are capped at MAX_GOALS
// to avoid pathological outliers (mirrors the offline pipeline's clamp).
const MAX_GOALS = 8;
function poissonSample(lambda) {
    // Guard against non-finite / non-positive input (missing ratings, NaN).
    if (!(lambda > 0)) return 0;
    // Clamp lambda so the Knuth loop can't run away on an extreme rating product.
    if (lambda > 10) lambda = 10;
    const L = Math.exp(-lambda);
    let k = 0;
    let p = 1;
    do {
        k++;
        p *= Math.random();
    } while (p > L);
    const goals = k - 1;
    return goals > MAX_GOALS ? MAX_GOALS : goals;
}

self.onmessage = function(e) {
    const { teams, fixtures, iterations, maxMatchday, ratings, homeAdvantage } = e.data;
    const teamCount = teams.length;
    const MAX_MATCHES = maxMatchday || 8;
    // Per-team attack/defense ratings keyed by team id (from data.json). Falls back
    // to an empty object; unrated teams get neutral lambdas below.
    const ratingMap = ratings || {};
    // Home advantage multiplier (data-driven when the dataset carries meta.home_advantage,
    // otherwise a sensible default). Applied only to the home side's expected goals.
    const HOME_ADV = (typeof homeAdvantage === 'number' && homeAdvantage > 0) ? homeAdvantage : 1.2;
    // Neutral fallback expected goals when a fixture's team has no rating entry,
    // preserving the previous model's slight home tilt.
    const DEFAULT_HOME_LAMBDA = 1.4;
    const DEFAULT_AWAY_LAMBDA = 1.1;

    // Map team ID to index for fast lookup
    const teamMap = {};
    teams.forEach((t, i) => teamMap[t.id] = i);

    // 1. CREATE PROJECTED STATE
    // We clone the base teams and apply the USER-DEFINED scores first.
    const projectedTeams = teams.map(t => ({ 
        ...t, 
        points: t.points, 
        gd: t.gd, 
        gf: t.gf, 
        played: t.played,
        form: t.form ? [...t.form] : [] 
    }));

    const unplayedFixtures = [];

    // Helper to update a team's stats
    const updateStats = (idx, gf, ga, result) => {
        if (idx === undefined) return;
        const t = projectedTeams[idx];
        t.played += 1;
        t.gf += gf;
        t.gd += (gf - ga);
        if (gf > ga) t.points += 3;
        else if (gf === ga) t.points += 1;

        // Update Form (simple append, we don't shift here to keep history, simulations will add more)
        t.form.push(result);
    };

    // Apply user inputs
    for (const match of fixtures) {
        if (typeof match.homeScore === 'number' && typeof match.awayScore === 'number') {
            let homeRes = 'D';
            let awayRes = 'D';
            if (match.homeScore > match.awayScore) { homeRes = 'W'; awayRes = 'L'; } 
            else if (match.awayScore > match.homeScore) { homeRes = 'L'; awayRes = 'W'; }

            updateStats(teamMap[match.home], match.homeScore, match.awayScore, homeRes);
            updateStats(teamMap[match.away], match.awayScore, match.homeScore, awayRes);
        } else {
            unplayedFixtures.push(match);
        }
    }

    // 2. PREPARE FOR MONTE CARLO
    // Structure: [points, gd, gf] * teamCount
    const baseStats = new Int32Array(teamCount * 3);
    for(let i=0; i<teamCount; i++) {
        baseStats[i*3] = projectedTeams[i].points;
        baseStats[i*3+1] = projectedTeams[i].gd;
        baseStats[i*3+2] = projectedTeams[i].gf;
    }

    // Output Arrays for Probabilities
    const top8Counts = new Uint32Array(teamCount);
    const top24Counts = new Uint32Array(teamCount);

    // Accumulators for Final Standings Projection (Points, GD, GF)
    // We use Float64 to prevent overflow before division
    const sumPoints = new Float64Array(teamCount);
    const sumGD = new Float64Array(teamCount);
    const sumGF = new Float64Array(teamCount);

    // Pre-allocate working arrays
    const currentStats = new Int32Array(teamCount * 3);
    const indices = new Int32Array(teamCount); // For sorting
    for(let i=0; i<teamCount; i++) indices[i] = i;

    // Simulation Loop
    for(let run=0; run<iterations; run++) {
        // Reset current stats to base
        currentStats.set(baseStats);

        // Simulate unplayed matches
        for(let i=0; i<unplayedFixtures.length; i++) {
            const m = unplayedFixtures[i];
            const homeIdx = teamMap[m.home];
            const awayIdx = teamMap[m.away];

            // Poisson-based goal generation using each team's attack/defense ratings.
            // Expected goals follow the standard multiplicative form used by the offline
            // pipeline: home_exp = home_attack * away_defense * home_advantage; the away
            // side gets no home-advantage boost. Teams without ratings fall back to
            // neutral lambdas so the sim never emits NaN.
            const homeRating = ratingMap[m.home];
            const awayRating = ratingMap[m.away];
            const homeLambda = (homeRating && awayRating)
                ? homeRating.attack * awayRating.defense * HOME_ADV
                : DEFAULT_HOME_LAMBDA;
            const awayLambda = (homeRating && awayRating)
                ? awayRating.attack * homeRating.defense
                : DEFAULT_AWAY_LAMBDA;
            const homeGoals = poissonSample(homeLambda);
            const awayGoals = poissonSample(awayLambda);

            // Update Home
            currentStats[homeIdx*3 + 2] += homeGoals; // GF
            currentStats[homeIdx*3 + 1] += (homeGoals - awayGoals); // GD
            if(homeGoals > awayGoals) currentStats[homeIdx*3] += 3; // Pts
            else if(homeGoals === awayGoals) currentStats[homeIdx*3] += 1;

            // Update Away
            currentStats[awayIdx*3 + 2] += awayGoals; // GF
            currentStats[awayIdx*3 + 1] += (awayGoals - homeGoals); // GD
            if(awayGoals > homeGoals) currentStats[awayIdx*3] += 3; // Pts
            else if(awayGoals === homeGoals) currentStats[awayIdx*3] += 1;
        }

        // Accumulate totals for averaging later
        for(let i=0; i<teamCount; i++) {
            sumPoints[i] += currentStats[i*3];
            sumGD[i] += currentStats[i*3+1];
            sumGF[i] += currentStats[i*3+2];
        }

        // Sort to find positions
        // We use a simple index sort to avoid object creation in the hot loop
        indices.sort((a, b) => {
            const ptrA = a * 3;
            const ptrB = b * 3;
            
            // Points
            if (currentStats[ptrB] !== currentStats[ptrA]) return currentStats[ptrB] - currentStats[ptrA];
            // GD
            if (currentStats[ptrB+1] !== currentStats[ptrA+1]) return currentStats[ptrB+1] - currentStats[ptrA+1];
            // GF
            return currentStats[ptrB+2] - currentStats[ptrA+2];
        });

        // Record Positions
        for(let rank=0; rank<teamCount; rank++) {
            const teamIdx = indices[rank];
            if (rank < 8) top8Counts[teamIdx]++;
            if (rank < 24) top24Counts[teamIdx]++;
        }

        // Progress
        if (run % 2000 === 0) {
            self.postMessage({ type: 'progress', value: Math.round((run / iterations) * 100) });
        }
    }

    // 3. AGGREGATE RESULTS
    const finalTeams = teams.map((t, i) => {
        return {
            ...t,
            // Set played to MAX_MATCHES because this is a completed simulation
            played: MAX_MATCHES,
            // Average projected stats
            points: Math.round(sumPoints[i] / iterations),
            gd: Math.round(sumGD[i] / iterations),
            gf: Math.round(sumGF[i] / iterations),
            // Probabilities
            top8_prob: (top8Counts[i] / iterations) * 100,
            top24_prob: (top24Counts[i] / iterations) * 100,
            // Keep form from base state (simulation doesn't easily average 'form' strings)
            form: projectedTeams[i].form.slice(-5)
        };
    });

    self.postMessage({ type: 'result', data: finalTeams });
};
